// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Enroll a tunnex-node agent with a join token
	// (POST /api/v1/agent/enroll)
	EnrollAgent(ctx context.Context, request EnrollAgentRequestObject) (EnrollAgentResponseObject, error)
	// Accept an invitation
	// (POST /api/v1/auth/invitations/accept)
	AcceptInvitation(ctx context.Context, request AcceptInvitationRequestObject) (AcceptInvitationResponseObject, error)
	// Verify credentials
	// (POST /api/v1/auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// Revoke the current session
	// (POST /api/v1/auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// The current authenticated user
	// (GET /api/v1/auth/me)
	CurrentUser(ctx context.Context, request CurrentUserRequestObject) (CurrentUserResponseObject, error)
	// Request a password-reset email
	// (POST /api/v1/auth/password-reset)
	RequestPasswordReset(ctx context.Context, request RequestPasswordResetRequestObject) (RequestPasswordResetResponseObject, error)
	// Set a new password using a reset token
	// (POST /api/v1/auth/password-reset/confirm)
	ConfirmPasswordReset(ctx context.Context, request ConfirmPasswordResetRequestObject) (ConfirmPasswordResetResponseObject, error)
	// Create a local account (sends a verification email)
	// (POST /api/v1/auth/signup)
	Signup(ctx context.Context, request SignupRequestObject) (SignupResponseObject, error)
	// SSO callback (enterprise)
	// (GET /api/v1/auth/sso/{provider}/callback)
	SsoCallback(ctx context.Context, request SsoCallbackRequestObject) (SsoCallbackResponseObject, error)
	// Begin an SSO login (enterprise)
	// (GET /api/v1/auth/sso/{provider}/start)
	StartSsoLogin(ctx context.Context, request StartSsoLoginRequestObject) (StartSsoLoginResponseObject, error)
	// Verify an email address with a token
	// (POST /api/v1/auth/verify-email)
	VerifyEmail(ctx context.Context, request VerifyEmailRequestObject) (VerifyEmailResponseObject, error)
	// Resend the current user's email-verification link
	// (POST /api/v1/auth/verify-email/resend)
	ResendVerification(ctx context.Context, request ResendVerificationRequestObject) (ResendVerificationResponseObject, error)
	// Public deployment metadata (edition, enabled SSO providers)
	// (GET /api/v1/meta)
	GetMeta(ctx context.Context, request GetMetaRequestObject) (GetMetaResponseObject, error)
	// List organizations
	// (GET /api/v1/organizations)
	ListOrganizations(ctx context.Context, request ListOrganizationsRequestObject) (ListOrganizationsResponseObject, error)
	// Create an organization
	// (POST /api/v1/organizations)
	CreateOrganization(ctx context.Context, request CreateOrganizationRequestObject) (CreateOrganizationResponseObject, error)
	// Soft-delete an organization
	// (DELETE /api/v1/organizations/{orgId})
	DeleteOrganization(ctx context.Context, request DeleteOrganizationRequestObject) (DeleteOrganizationResponseObject, error)
	// Get an organization
	// (GET /api/v1/organizations/{orgId})
	GetOrganization(ctx context.Context, request GetOrganizationRequestObject) (GetOrganizationResponseObject, error)
	// Update organization settings (name only; slug is immutable)
	// (PATCH /api/v1/organizations/{orgId})
	UpdateOrganization(ctx context.Context, request UpdateOrganizationRequestObject) (UpdateOrganizationResponseObject, error)
	// List devices (own devices for members; all for admins)
	// (GET /api/v1/organizations/{orgId}/devices)
	ListDevices(ctx context.Context, request ListDevicesRequestObject) (ListDevicesResponseObject, error)
	// Create a device/peer bound to the owning user
	// (POST /api/v1/organizations/{orgId}/devices)
	CreateDevice(ctx context.Context, request CreateDeviceRequestObject) (CreateDeviceResponseObject, error)
	// Revoke a device (peer removed from the gateway within seconds)
	// (POST /api/v1/organizations/{orgId}/devices/{deviceId}/revoke)
	RevokeDevice(ctx context.Context, request RevokeDeviceRequestObject) (RevokeDeviceResponseObject, error)
	// Claim an email domain for capture (enterprise)
	// (POST /api/v1/organizations/{orgId}/domains)
	CreateDomainClaim(ctx context.Context, request CreateDomainClaimRequestObject) (CreateDomainClaimResponseObject, error)
	// Verify a claimed domain via its DNS TXT record (enterprise)
	// (POST /api/v1/organizations/{orgId}/domains/verify)
	VerifyDomainClaim(ctx context.Context, request VerifyDomainClaimRequestObject) (VerifyDomainClaimResponseObject, error)
	// Invite a user to the organization
	// (POST /api/v1/organizations/{orgId}/invitations)
	CreateInvitation(ctx context.Context, request CreateInvitationRequestObject) (CreateInvitationResponseObject, error)
	// Resend an invitation (new token, old invalidated)
	// (POST /api/v1/organizations/{orgId}/invitations/resend)
	ResendInvitation(ctx context.Context, request ResendInvitationRequestObject) (ResendInvitationResponseObject, error)
	// Revoke a pending invitation
	// (POST /api/v1/organizations/{orgId}/invitations/revoke)
	RevokeInvitation(ctx context.Context, request RevokeInvitationRequestObject) (RevokeInvitationResponseObject, error)
	// List the organization's members (roster incl. deactivated)
	// (GET /api/v1/organizations/{orgId}/members)
	ListMembers(ctx context.Context, request ListMembersRequestObject) (ListMembersResponseObject, error)
	// Deactivate a member's account (freezes access, revokes sessions)
	// (POST /api/v1/organizations/{orgId}/members/{userId}/deactivate)
	DeactivateMember(ctx context.Context, request DeactivateMemberRequestObject) (DeactivateMemberResponseObject, error)
	// Reactivate a deactivated member
	// (POST /api/v1/organizations/{orgId}/members/{userId}/reactivate)
	ReactivateMember(ctx context.Context, request ReactivateMemberRequestObject) (ReactivateMemberResponseObject, error)
	// Change a member's role (RBAC-gated; refuses demoting the last owner)
	// (PUT /api/v1/organizations/{orgId}/members/{userId}/role)
	ChangeMemberRole(ctx context.Context, request ChangeMemberRoleRequestObject) (ChangeMemberRoleResponseObject, error)
	// List enrolled nodes
	// (GET /api/v1/organizations/{orgId}/nodes)
	ListNodes(ctx context.Context, request ListNodesRequestObject) (ListNodesResponseObject, error)
	// Issue a single-use node join token
	// (POST /api/v1/organizations/{orgId}/nodes/join-token)
	IssueJoinToken(ctx context.Context, request IssueJoinTokenRequestObject) (IssueJoinTokenResponseObject, error)
	// Revoke a node (renewal will be refused)
	// (POST /api/v1/organizations/{orgId}/nodes/{nodeId}/revoke)
	RevokeNode(ctx context.Context, request RevokeNodeRequestObject) (RevokeNodeResponseObject, error)
	// Dashboard overview — counts + recent activity
	// (GET /api/v1/organizations/{orgId}/overview)
	GetOrgOverview(ctx context.Context, request GetOrgOverviewRequestObject) (GetOrgOverviewResponseObject, error)
	// Read an SSO provider's config (enterprise) — never returns the secret
	// (GET /api/v1/organizations/{orgId}/sso/{provider})
	GetSsoConfig(ctx context.Context, request GetSsoConfigRequestObject) (GetSsoConfigResponseObject, error)
	// Configure an SSO provider for an organization (enterprise)
	// (PUT /api/v1/organizations/{orgId}/sso/{provider})
	SetSsoConfig(ctx context.Context, request SetSsoConfigRequestObject) (SetSsoConfigResponseObject, error)
	// Liveness probe
	// (GET /healthz)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// EnrollAgent operation middleware
func (sh *strictHandler) EnrollAgent(w http.ResponseWriter, r *http.Request) {
	var request EnrollAgentRequestObject

	var body EnrollAgentJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.EnrollAgent(ctx, request.(EnrollAgentRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "EnrollAgent")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(EnrollAgentResponseObject); ok {
		if err := validResponse.VisitEnrollAgentResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

